import { useState, useEffect } from 'react';
import './App.css';

// 🚀 Use your CloudFront Distribution URL as the single entry point
// بدلاً من الرابط الثابت:
const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || "http://localhost:8080";
function App() {
  const [products, setProducts] = useState([]);
  const [cart, setCart] = useState([]);
  const [authToken, setAuthToken] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showCart, setShowCart] = useState(false);

  const [newProduct, setNewProduct] = useState({ name: '', price: '', file: null });
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchProducts();
    checkActiveSession();
  }, []);

  // Utility: Decode JWT Payload without external libraries
  const decodeJWT = (token) => {
    try {
      const base64Url = token.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(window.atob(base64).split('').map(function(c) {
        return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
      }).join(''));
      return JSON.parse(jsonPayload);
    } catch (e) { return null; }
  };

  const checkActiveSession = () => {
    const savedToken = localStorage.getItem('cognito_jwt_token');
    if (savedToken) {
      setAuthToken(savedToken);
      const decoded = decodeJWT(savedToken);
      if (decoded) {
        const groups = decoded["cognito:groups"] || [];
        setIsAdmin(groups.includes("Admins"));
      }
    }
  };

  const handleLoginSimulation = (role) => {
    const tokenPayload = role === 'admin' 
      ? { "cognito:groups": ["Admins"], username: "admin_user" } 
      : { username: "regular_user" };

    const dummyToken = `eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.${window.btoa(JSON.stringify(tokenPayload))}.dummy_sig`;
    localStorage.setItem('cognito_jwt_token', dummyToken);
    setAuthToken(dummyToken);
    checkActiveSession();
  };

  const handleLogout = () => {
    localStorage.removeItem('cognito_jwt_token');
    setAuthToken(null);
    setIsAdmin(false);
  };

  const fetchProducts = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/products`);
      if (response.ok) setProducts(await response.json());
    } catch (error) {
      setProducts([
        { id: 1, name: "Network Laptop", price: 1500, image_url: "https://via.placeholder.com/150" },
        { id: 2, name: "Cisco Router", price: 450, image_url: "https://via.placeholder.com/150" }
      ]);
    }
  };

  const handleAddProduct = async (e) => {
    e.preventDefault();
    setUploading(true);
    try {
      const urlResponse = await fetch(`${API_BASE_URL}/admin/products/upload-url`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ file_name: newProduct.file.name })
      });
      const { upload_url, file_url } = await urlResponse.json();

      await fetch(upload_url, { method: 'PUT', body: newProduct.file });

      await fetch(`${API_BASE_URL}/admin/products`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newProduct.name, price: newProduct.price, image_url: file_url })
      });
      alert("Product added successfully via Fargate & S3!");
      fetchProducts();
    } catch (e) { alert("Operation failed."); }
    finally { setUploading(false); }
  };

  const handleCheckout = async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/checkout`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ items: cart, total: cart.reduce((s, i) => s + i.price, 0) })
      });
      if (response.ok) {
        alert("Order submitted to SQS pipeline via API Gateway & Lambda!");
        setCart([]); setShowCart(false);
      }
    } catch (e) { alert("Checkout failed."); }
  };
  const [bestSellers, setBestSellers] = useState([]);

useEffect(() => {
  fetch(`${API_BASE_URL}/best-sellers`)
    .then(res => res.json())
    .then(data => setBestSellers(data))
    .catch(err => console.log("Best sellers not loaded"));
}, []);

// وفي الـ Return بتاع الـ JSX:


  return (
    <div style={{ fontFamily: 'Arial, sans-serif', padding: '20px', backgroundColor: '#f8fafc', minHeight: '100vh' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', background: '#0f172a', color: 'white', padding: '15px 30px', borderRadius: '8px' }}>
        <h2>Cloud Store ☁️</h2>
        <div>
          {!authToken ? (
            <>
              <button onClick={() => handleLoginSimulation('user')}>Login as User</button>
              <button onClick={() => handleLoginSimulation('admin')} style={{marginLeft: '10px'}}>Login as Admin</button>
            </>
          ) : <button onClick={handleLogout}>Logout</button>}
          <button onClick={() => setShowCart(!showCart)} style={{marginLeft: '15px'}}>Cart ({cart.length})</button>
        </div>
      </header>

      {showCart && (
        <div style={{ background: 'white', padding: '20px', marginTop: '20px', borderRadius: '8px' }}>
          <h3>Shopping Cart</h3>
          {cart.map((item, idx) => <p key={idx}>{item.name} - ${item.price}</p>)}
          <button onClick={handleCheckout} style={{ background: '#10b981', color: 'white', border: 'none', padding: '10px', width: '100%' }}>Checkout (Serverless API Gateway & Lambda)</button>
        </div>
      )}

      {isAdmin && (
        <section style={{ background: '#fffbeb', padding: '20px', borderRadius: '8px', marginTop: '30px' }}>
          <h3>🛡️ Admin Dashboard (ECS Fargate & S3)</h3>
          <form onSubmit={handleAddProduct} style={{ display: 'flex', gap: '10px' }}>
            <input placeholder="Name" onChange={e => setNewProduct({...newProduct, name: e.target.value})} required />
            <input type="number" placeholder="Price" onChange={e => setNewProduct({...newProduct, price: e.target.value})} required />
            <input type="file" onChange={e => setNewProduct({...newProduct, file: e.target.files[0]})} required />
            <button type="submit" disabled={uploading}>Add Product</button>
          </form>
        </section>
      )}

      <h3>📦 Product Catalog</h3>
      <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
        {products.map(p => (
          <div key={p.id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '8px', width: '200px' }}>
            <img src={p.image_url} alt={p.name} style={{ width: '100%', height: '120px' }} />
            <h4>{p.name}</h4>
            <p>${p.price}</p>
            <button onClick={() => setCart([...cart, p])}>Add to Cart</button>
          </div>
        ))}
      </div>
      <h3>🔥 Best Sellers</h3>
        <div style={{ display: 'flex', gap: '10px' }}>
          {bestSellers.map(p => (
            <div key={p.id} style={{ border: '1px solid #f59e0b', padding: '10px' }}>
              {p.name}
            </div>
          ))}
        </div>
    </div>
  );
}

export default App;
